/**
 * Provides OAuth credentials from secure sources.
 * Credentials should be stored in one of:
 *   1. Android Keystore / EncryptedSharedPreferences
 *   2. A remote secrets manager (e.g., AWS Secrets Manager, HashiCorp Vault)
 *   3. Server-side proxy (recommended: never expose client secrets on device)
 *
 * For client secrets specifically, the recommended approach is to NEVER store them
 * on the device. Instead, use a backend server to handle the OAuth token exchange.
 */
class SecureCredentialProvider(private val context: Context) {

    companion object {
        private const val TAG = "SecureCredentialProvider"
        private const val PREFS_NAME = "social_login_config"

        // Keys for EncryptedSharedPreferences - these are key names, NOT secrets
        private const val KEY_FACEBOOK_APP_ID = "facebook_app_id"
        private const val KEY_GOOGLE_CLIENT_ID = "google_client_id"
        // Client secrets should NOT be stored on device at all.
        // Token exchange should happen server-side.
    }

    private val encryptedPrefs: android.content.SharedPreferences by lazy {
        androidx.security.crypto.EncryptedSharedPreferences.create(
            PREFS_NAME,
            androidx.security.crypto.MasterKeys.getOrCreate(
                androidx.security.crypto.MasterKeys.AES256_GCM_SPEC
            ),
            context,
            androidx.security.crypto.EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            androidx.security.crypto.EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    /**
     * Retrieves the Facebook App ID from encrypted storage.
     * This must be provisioned during app setup / first launch via a secure channel.
     */
    fun getFacebookAppId(): String {
        return encryptedPrefs.getString(KEY_FACEBOOK_APP_ID, null)
            ?: throw IllegalStateException(
                "Facebook App ID not configured. Call configureFacebookAppId() first."
            )
    }

    /**
     * Retrieves the Google OAuth Client ID from encrypted storage.
     */
    fun getGoogleClientId(): String {
        return encryptedPrefs.getString(KEY_GOOGLE_CLIENT_ID, null)
            ?: throw IllegalStateException(
                "Google Client ID not configured. Call configureGoogleClientId() first."
            )
    }

    /**
     * Stores the Facebook App ID in encrypted storage.
     * Should be called during secure provisioning (e.g., fetched from your backend).
     */
    fun configureFacebookAppId(appId: String) {
        require(appId.isNotBlank()) { "Facebook App ID must not be blank" }
        encryptedPrefs.edit().putString(KEY_FACEBOOK_APP_ID, appId).apply()
    }

    /**
     * Stores the Google Client ID in encrypted storage.
     * Should be called during secure provisioning (e.g., fetched from your backend).
     */
    fun configureGoogleClientId(clientId: String) {
        require(clientId.isNotBlank()) { "Google Client ID must not be blank" }
        encryptedPrefs.edit().putString(KEY_GOOGLE_CLIENT_ID, clientId).apply()
    }

    /**
     * Checks whether all required credentials have been provisioned.
     */
    fun isConfigured(): Boolean {
        return encryptedPrefs.getString(KEY_FACEBOOK_APP_ID, null) != null &&
                encryptedPrefs.getString(KEY_GOOGLE_CLIENT_ID, null) != null
    }

    /**
     * Clears all stored credentials (e.g., on logout or re-provisioning).
     */
    fun clearCredentials() {
        encryptedPrefs.edit().clear().apply()
    }
}

