// --- Main Social Login Module ---

class SocialLoginModule private constructor(
    private val credentialProvider: SecureCredentialProvider,
    private val facebookHandler: FacebookLoginHandler,
    private val googleHandler: GoogleLoginHandler
) {

    companion object {
        private const val TAG = "SocialLoginModule"

        /**
         * Creates a SocialLoginModule instance.
         *
         * @param context Application context
         * @param serverBaseUrl Your backend server URL for OAuth token exchange.
         *                      The server holds all client secrets securely.
         */
        fun create(context: Context, serverBaseUrl: String): SocialLoginModule {
            require(serverBaseUrl.startsWith("https://")) {
                "Server base URL must use HTTPS"
            }

            val credentialProvider = SecureCredentialProvider(context)
            val tokenExchangeUrl = "$serverBaseUrl/api/v1/oauth/exchange"

            return SocialLoginModule(
                credentialProvider = credentialProvider,
                facebookHandler = FacebookLoginHandler(credentialProvider, tokenExchangeUrl),
                googleHandler = GoogleLoginHandler(credentialProvider, tokenExchangeUrl)
            )
        }
    }

    /**
     * Provisions OAuth client IDs fetched from a secure source.
     * Call this during app initialization after fetching config from your backend.
     */
    fun provisionCredentials(facebookAppId: String, googleClientId: String) {
        credentialProvider.configureFacebookAppId(facebookAppId)
        credentialProvider.configureGoogleClientId(googleClientId)
        Log.d(TAG, "OAuth credentials provisioned securely")
    }

    /**
     * Checks if the module has been properly configured with credentials.
     */
    fun isConfigured(): Boolean = credentialProvider.isConfigured()

    /**
     * Initializes the social login providers. Must be called after provisionCredentials().
     */
    fun initialize(context: Context) {
        check(isConfigured()) {
            "SocialLoginModule not configured. Call provisionCredentials() first, " +
                    "or use RemoteConfigService to fetch credentials from your backend."
        }
        facebookHandler.initialize(context)
        Log.d(TAG, "Social login module initialized")
    }

    /**
     * Initiates Facebook login.
     */
    fun loginWithFacebook(activity: AppCompatActivity, callback: SocialAuthCallback) {
        facebookHandler.login(activity, callback)
    }

    /**
     * Gets the Google Sign-In intent.
     */
    fun getGoogleSignInIntent(context: Context): Intent {
        return googleHandler.getSignInIntent(context)
    }

    /**
     * Handles the Google Sign-In result.
     */
    fun handleGoogleSignInResult(data: Intent?, callback: SocialAuthCallback) {
        googleHandler.handleSignInResult(data, callback)
    }

    /**
     * Logs out from all providers and clears stored credentials.
     */
    fun logout() {
        credentialProvider.clearCredentials()
        Log.d(TAG, "Logged out and cleared credentials")
    }
}

