/**
 * Example showing how to use the SocialLoginModule securely.
 *
 * Key security principles:
 * 1. OAuth client secrets are NEVER stored on the device
 * 2. Token exchange happens on your backend server
 * 3. Client IDs are fetched from a secure backend, not hardcoded
 * 4. Credentials are stored in EncryptedSharedPreferences on device
 * 5. All communication uses HTTPS
 */
class LoginActivity : AppCompatActivity(), SocialAuthCallback {

    private lateinit var socialLogin: SocialLoginModule

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        // Create the module pointing to your secure backend
        socialLogin = SocialLoginModule.create(
            context = applicationContext,
            serverBaseUrl = "https://api.yourapp.com"  // Your backend server
        )

        // Fetch OAuth config from your backend (which holds the secrets)
        val remoteConfig = RemoteConfigService()
        remoteConfig.fetchOAuthConfig(
            baseUrl = "https://api.yourapp.com",
            callback = object : RemoteConfigService.Callback {
                override fun onConfigLoaded(facebookAppId: String, googleClientId: String) {
                    // Store the public client IDs securely on device
                    socialLogin.provisionCredentials(facebookAppId, googleClientId)
                    socialLogin.initialize(this@LoginActivity)
                }

                override fun onError(error: Throwable) {
                    Log.e("LoginActivity", "Failed to load OAuth config", error)
                    // Handle error - show retry UI, etc.
                }
            }
        )
    }

    fun onFacebookLoginClicked() {
        socialLogin.loginWithFacebook(this, this)
    }

    fun onGoogleLoginClicked() {
        val intent = socialLogin.getGoogleSignInIntent(this)
        // Launch with ActivityResultLauncher
    }

    override fun onAuthResult(result: AuthResult) {
        when (result) {
            is AuthResult.Success -> {
                Log.d("LoginActivity", "Login successful with ${result.provider}")
                // Navigate to main screen
            }
            is AuthResult.Error -> {
                Log.e("LoginActivity", "Login failed: ${result.message}")
                // Show error to user
            }
            is AuthResult.Cancelled -> {
                Log.d("LoginActivity", "Login cancelled")
            }
        }
    }
}